'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneCardProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    maxSize?: number;
    defaultImage?: string;
}

export function AvatarDropzoneCard({
    className,
    onFileSelect,
    maxSize = 5 * 1024 * 1024,
    defaultImage,
}: AvatarDropzoneCardProps) {
    return (
        <SingleImageDrop
            variant="card"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            label="Profile Photo"
            showProgress={true}
            showRemoveButton={true}
            className={className}
        />
    );
}
